) -> LinuxResult<isize> {
    check_sigset_size(sigsetsize)?;

    let sig = make_queue_signal_info(tgid, signo, sig)?;
    send_signal_process(get_process(tgid)?.as_ref(), sig)?;
    Ok(0)
}

