#[cfg(target_arch = "x86_64")]
pub fn sys_access(path: UserConstPtr<c_char>, mode: u32) -> LinuxResult<isize> {
    use linux_raw_sys::general::AT_FDCWD;

    sys_faccessat2(AT_FDCWD, path, mode, 0)
}

pub fn sys_faccessat2(
    dirfd: c_int,
    path: UserConstPtr<c_char>,
    mode: u32,
    flags: u32,
) -> LinuxResult<isize> {
    let path = nullable!(path.get_as_str())?;

    if mode == 0 {
        return Ok(0);
    };

    let mode = AccessFlags::from_bits(mode).ok_or(LinuxError::EINVAL)?;
    let path = resolve_path_with_parent(dirfd, path.unwrap())?;
    let mut options = OpenOptions::new();
    options.read(true);
    let permissions = if let Ok(file) = axfs::fops::File::open(&path, &options) {
        file.get_attr()?.perm()
    } else if let Ok(dir) = axfs::fops::Directory::open_dir(&path, &options) {
        dir.get_attr()?.perm()
    } else {
        return Err(LinuxError::ENOENT);
    };

    let mut access = true;
    if mode.contains(AccessFlags::R_OK) {
        access |= permissions.owner_readable();
    }
    if mode.contains(AccessFlags::W_OK) {
        access |= permissions.owner_writable();
    }
    if mode.contains(AccessFlags::X_OK) {
        access |= permissions.owner_executable();
    }

    if access {
        Ok(0)
    } else {
        Err(LinuxError::EACCES)
    }
}

bitflags! {
    #[derive(Debug)]
    pub struct AccessFlags: u32 {
        const R_OK = R_OK;
        const W_OK = W_OK;
        const X_OK = X_OK;
    }
}

use axerrno::{LinuxError, LinuxResult};
use axtask::{TaskExtRef, current};
use linux_raw_sys::general::{
    FUTEX_CMD_MASK, FUTEX_CMP_REQUEUE, FUTEX_REQUEUE, FUTEX_WAIT, FUTEX_WAKE, timespec,
};

use crate::{
    ptr::{UserConstPtr, UserPtr, nullable},
    time::TimeValueLike,
};

pub fn sys_futex(
    uaddr: UserConstPtr<u32>,
    futex_op: u32,
    value: u32,
    timeout: UserConstPtr<timespec>,
    uaddr2: UserPtr<u32>,
    value3: u32,
) -> LinuxResult<isize> {
    info!("futex {:?} {} {}", uaddr.address(), futex_op, value);

    let curr = current();
    let futex_table = &curr.task_ext().process_data().futex_table;

    let addr = uaddr.address().as_usize();
    let command = futex_op & (FUTEX_CMD_MASK as u32);
    match command {
        FUTEX_WAIT => {
            if *uaddr.get_as_ref()? != value {
                return Err(LinuxError::EAGAIN);
            }
            let wq = futex_table.get_or_insert(addr);

            if let Some(timeout) = nullable!(timeout.get_as_ref())? {
                wq.wait_timeout(timeout.to_time_value());
            } else {
                wq.wait();
            }

            Ok(0)
        }
        FUTEX_WAKE => {
            let wq = futex_table.get(addr);
            let mut count = 0;
            if let Some(wq) = wq {
                for _ in 0..value {
                    if !wq.notify_one(false) {
                        break;
                    }
                    count += 1;
                }
            }
            axtask::yield_now();
            Ok(count)
        }
        FUTEX_REQUEUE | FUTEX_CMP_REQUEUE => {
            if command == FUTEX_CMP_REQUEUE && *uaddr.get_as_ref()? != value3 {
                return Err(LinuxError::EAGAIN);
            }
            let value2 = timeout.address().as_usize() as u32;

            let wq = futex_table.get(addr);
            let wq2 = futex_table.get_or_insert(uaddr2.address().as_usize());

            let mut count = 0;
            if let Some(wq) = wq {
                for _ in 0..value {
                    if !wq.notify_one(false) {
                        break;
                    }
                    count += 1;
                }
                if count == value as isize {
                    count += wq.requeue(value2 as usize, &wq2) as isize;
                }
            }
            Ok(count)
        }
        _ => Err(LinuxError::ENOSYS),
    }
}
